2. In http-routes.ts, replace the rate limiter with coalescing logic in handleReload:
```
const RELOAD_COALESCE_MS = 500;

const handleReload = async (req, state, sessionServers, transports) => {
  // Auth checked per-request BEFORE coalescing
  const authError = checkBearerAuth(req, state.wsSecret);
  if (authError) return authError;

  // If a pending coalesced reload exists, reset the debounce timer and share its promise
  if (state.pendingReload) {
    clearTimeout(state.pendingReload.timer);
    const pending = state.pendingReload;
    pending.timer = setTimeout(() => executeCoalescedReload(state, sessionServers, transports), RELOAD_COALESCE_MS);
    try {
      const result = await pending.promise;
      return Response.json({ ok: true, plugins: result.plugins, durationMs: result.durationMs });
    } catch (err) {
      return Response.json({ ok: false, error: sanitizeErrorMessage(toErrorMessage(err)) }, { status: 500 });
    }
  }

  // First request: create the coalescing entry
  let resolve!: (r: { plugins: number; durationMs: number }) => void;
  let reject!: (e: Error) => void;
  const promise = new Promise<{ plugins: number; durationMs: number }>((res, rej) => {
    resolve = res;
    reject = rej;
  });
  const timer = setTimeout(() => executeCoalescedReload(state, sessionServers, transports), RELOAD_COALESCE_MS);
  state.pendingReload = { promise, resolve, reject, timer };

  try {
    const result = await promise;
    return Response.json({ ok: true, plugins: result.plugins, durationMs: result.durationMs });
  } catch (err) {
    return Response.json({ ok: false, error: sanitizeErrorMessage(toErrorMessage(err)) }, { status: 500 });
  }
};

const executeCoalescedReload = async (state, sessionServers, transports) => {
  const pending = state.pendingReload;
  if (!pending) return;
  state.pendingReload = null;
  try {
    const result = await performConfigReload(state, sessionServers, transports);
    pending.resolve(result);
  } catch (err) {
    pending.reject(err instanceof Error ? err : new Error(String(err)));
  }
};
```

Constraints:
- Do NOT remove checkEndpointRateLimit function — other endpoints use it.
- Do NOT change rate limiting on any other endpoint.
- The coalescing state MUST be on ServerState (not module-level) to survive hot reload.
- The response shape { ok, plugins, durationMs } must be identical to current behavior.
- performConfigReload's serialization chain (reload.ts) still applies — coalescing happens at the HTTP layer before performConfigReload is called.

Traps:
- The timer callback must handle the case where state.pendingReload is already null (e.g., if the server shuts down mid-debounce).
- Error handling: if performConfigReload throws, ALL coalesced callers must receive the error response.

